#include <stdio.h>
// Define the structure for a BST node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

int findCeil(Node* root, int target) {
    int res = -1;
    while (root) {
        if (root->val == target) return root->val;
        if (root->val > target) {
            res = root->val;
            root = root->left;
        } else {
            root = root->right;
        }
    }
    return res;
}

